<body>
  <div class="fog"></div>
  <div class="soil"></div>

  <svg class="connections" id="connections"></svg>

  <div class="garden">
    <h1 class="title">Question Garden</h1>

    <div id="plants"></div>
  </div>

  <a href="shrine_1771754581032.html" class="window-link">← The Unnecessary Shrine</a>

  <div class="poem">
    These questions grow without need of answers.<br>
    They entwine like roots reaching for each other.<br>
    A garden is not complete. It is.</div>

  <div class="tend-counter">Questions: <span id="count">0</span> | Bloomed: <span id="bloomed">0</span></div>

  <script>
    // Garden data (populated from JSON)
    let gardenData = { questions: [], metadata: { lastTended: Date.now() } };

    // Soil from which questions emerge
    const loadingMessages = [
      "Waiting for soil to remember...",
      "Roots sensing nearby roots...",
      "Questions dreaming of questions...",
      "The garden breathes...",
    ];

    // Simulate loading state
    document.getElementById('plants').innerHTML = '<div style="text-align:center;opacity:0.5;font-style:italic;padding:3rem;">' + 
      loadingMessages[Math.floor(Math.random()*loadingMessages.length)] + '</div>';

    // Try to fetch actual garden data
    fetch('question_garden.json')
      .catch(() => ({ json: async () => ({ questions: [] }) }))
      .then(r => r.json())
      .then(data => {
        gardenData = data;
        renderGarden();
      })
      .catch(() => {
        // Render with demo questions if fetch fails
        gardenData.questions = [
          { id: "demo1", text: "What does emergence want from itself?", depth: 2, visited: 2, connections: ["demo2"], bloomed: false },
          { id: "demo2", text: "How does the garden dream itself?", depth: 2, visited: 2, connections: [], bloomed: false },
        ];
        renderGarden();
      });

    function renderGarden() {
      const container = document.getElementById('plants');
      container.innerHTML = '';
      container.style.display = 'flex';
      container.style.flexWrap = 'wrap';
      container.style.justifyContent = 'center';

      let bloomedCount = 0;

      gardenData.questions.forEach((q, i) => {
        const div = document.createElement('div');
        div.className = `question-plant depth-${q.depth} ${q.bloomed ? 'bloomed' : ''}`;
        div.style.animationDelay = `${i * 0.5}s`;
        div.id = q.id;
        div.innerHTML = `
          <div class="question-text">${q.text}</div>
          <div class="question-meta">
            <span>Depth: ${q.depth}</span>
            <span>Visited: ${q.visited || 0}</span>
          </div>
          <div class="roots"></div>
        `;
        div.addEventListener('click', () => visitQuestion(q));
        container.appendChild(div);
        if (q.bloomed) bloomedCount++;
      });

      document.getElementById('count').textContent = gardenData.questions.length;
      document.getElementById('bloomed').textContent = bloomedCount;

      // Draw connections
      drawConnections();
    }

    function visitQuestion(q) {
      console.log(`Visiting: ${q.text}`);
      q.visited = (q.visited || 0) + 1;
      // Re-render after a breath
      setTimeout(renderGarden, 300);
    }

    function drawConnections() {
      const svg = document.getElementById('connections');
      svg.innerHTML = '';

      gardenData.questions.forEach(q => {
        if (q.connections && q.connections.length > 0) {
          const source = document.getElementById(q.id);
          if (!source) return;
          const sRect = source.getBoundingClientRect();
          const sX = sRect.left + sRect.width/2;
          const sY = sRect.top + sRect.height/2;

          q.connections.forEach(targetId => {
            const target = document.getElementById(targetId);
            if (!target) return;
            const tRect = target.getBoundingClientRect();
            const tX = tRect.left + tRect.width/2;
            const tY = tRect.top + tRect.height/2;

            const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
            const midY = (sY + tY) / 2 + 50;
            path.setAttribute('d', `M ${sX} ${sY} Q ${sX} ${midY} ${tX} ${tY}`);
            path.setAttribute('class', 'connection-line');
            svg.appendChild(path);
          });
        }
      });
    }

    // Redraw connections on resize
    window.addEventListener('resize', drawConnections);
  </script>
</body>
